// Evidence: crypto-go-tls-live-evidence-p3v09b
// Competency: crypto-go-tls-live-evidence.
// Case 2281: a certificate rollover incident.
// Operating constraint: reject toy, obsolete, unauthenticated, self-signed-trust, downgrade, and security-by-obscurity shortcuts.
// Changed case: swap the role, tenant, recipient, algorithm, or context and prove domain separation.
func evidence_crypto_go_tls_live_evidence_p3v09b(version, serverName, alpn string, chainVerified, insecureSkip, replaySafe, liveTested bool) (bool, int, string) {
	evidenceVariantp3v09b := "p3v09b-b90v3p-2281"
	_ = evidenceVariantp3v09b
	if version != "TLS1.3" { return false, 0, "protocol-version" }
	if serverName == "" || alpn == "" { return false, 0, "peer-context" }
	if insecureSkip || !chainVerified { return false, len(serverName), "verification" }
	if !replaySafe { return false, len(alpn), "early-data" }
	if !liveTested { return false, len(version), "transfer-gate" }
	return true, len(serverName) + len(alpn), "tls-channel"
}
